module div_8bit (
    input clk, rst, sign, opn_valid, res_ready,
    input [7:0] dividend, divisor,
    output reg res_valid,
    output reg [15:0] result
);

reg [7:0] dividend_reg, divisor_reg;
reg [15:0] sr; 
reg [15:0] neg_divisor; 
reg [3:0] cnt; 
reg start_cnt; 
wire [15:0] sub_result; 
wire carry_out; 

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        dividend_reg <= 8'b0;
        divisor_reg <= 8'b0;
    end else if (opn_valid && !res_valid) begin
        dividend_reg <= dividend;
        divisor_reg <= divisor;
    end
end

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        sr <= 16'b0;
        neg_divisor <= 16'b0;
        cnt <= 4'b0;
        start_cnt <= 1'b0;
    end else if (opn_valid && !res_valid) begin
        sr <= {{8{dividend_reg[7]}}, dividend_reg} << 1; 
        neg_divisor <= -$signed({8'b0, divisor_reg}); 
        cnt <= 4'd1; 
        start_cnt <= 1'b1; 
    end else if (start_cnt) begin
        if (cnt[3]) begin 
            cnt <= 4'b0; 
            start_cnt <= 1'b0; 
            result <= sr; 
        end else begin
            cnt <= cnt + 1; 
            sr <= {sr[14:0], carry_out}; 
        end
    end
end

assign {carry_out, sub_result} = sr + neg_divisor; 

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        sr <= 16'b0;
    end else if (start_cnt) begin
        sr <= {sr[14:0], carry_out};
    end
end

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        res_valid <= 1'b0;
    end else if (cnt == 4'd8) begin
        res_valid <= 1'b1; 
    end else if (res_valid && res_ready) begin
        res_valid <= 1'b0; 
    end
end
endmodule
